1	const BASE_PRICES: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	
10	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
11	const SUBSEQUENT_CONTRACT_DISCOUNT_PERCENT = 15;
12	const FIXED_FEE = 5;
13	const ALIKE_COMPONENT_BLOCK_SIZE = 3;
14	const ALIKE_COMPONENT_BLOCK_PRICE = 60;
15	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
16	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATIO = 0.5;
17	const DRAGON_MATERIAL = "dragon";
18	const DRAGON_REIMBURSEMENT_RATIO = 1;
19	const CLAIM_DEDUCTIBLE = 100;
20	
21	function applyFirstInsuranceSurcharge(amount: number): number {
22	  return Math.ceil((amount * (100 + FIRST_INSURANCE_SURCHARGE_PERCENT)) / 100);
23	}
24	
25	function applySubsequentContractDiscount(amount: number): number {
26	  return Math.ceil((amount * (100 - SUBSEQUENT_CONTRACT_DISCOUNT_PERCENT)) / 100);
27	}
28	
29	function countByType(items: { type: string }[]): Record<string, number> {
30	  return items.reduce<Record<string, number>>((counts, item) => {
31	    counts[item.type] = (counts[item.type] ?? 0) + 1;
32	    return counts;
33	  }, {});
34	}
35	
36	function priceForType(type: string, count: number): number {
37	  const blocks = Math.floor(count / ALIKE_COMPONENT_BLOCK_SIZE);
38	  const leftover = count % ALIKE_COMPONENT_BLOCK_SIZE;
39	  return blocks * ALIKE_COMPONENT_BLOCK_PRICE + leftover * BASE_PRICES[type];
40	}
41	
42	function quoteBasePrice(items: { type: string }[]): number {
43	  const counts = countByType(items);
44	  return Object.entries(counts).reduce(
45	    (total, [type, count]) => total + priceForType(type, count),
46	    0
47	  );
48	}
49	
50	function applyRatioIf(
51	  condition: boolean,
52	  basePrice: number,
53	  numerator: number,
54	  denominator: number
55	): number {
56	  return condition ? Math.ceil((basePrice * numerator) / denominator) : basePrice;
57	}
58	
59	function applyCursedSurcharge(items: { cursed: boolean }[], basePrice: number): number {
60	  const hasCursed = items.some((item) => item.cursed);
61	  return applyRatioIf(hasCursed, basePrice, 3, 2);
62	}
63	
64	function applyEnchantedSurcharge(items: { enchantment: number }[], basePrice: number): number {
65	  const hasHighEnchant = items.some((item) => item.enchantment >= 5);
66	  return applyRatioIf(hasHighEnchant, basePrice, 13, 10);
67	}
68	
69	function applyLoyaltyDiscount(yearsWithMHPCO: number, basePrice: number): number {
70	  return applyRatioIf(yearsWithMHPCO >= 2, basePrice, 8, 10);
71	}
72	
73	function reimbursementRatio(item: any): number {
74	  if (item.material === DRAGON_MATERIAL) return DRAGON_REIMBURSEMENT_RATIO;
75	  if (item.enchantment >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD)
76	    return HIGH_ENCHANTMENT_REIMBURSEMENT_RATIO;
77	  return 0;
78	}
79	
80	function computeClaimPayout(scenario: any, step: any): number {
81	  const policyStep = scenario.steps[step.policy];
82	  const damage = step.damages[0];
83	  const item = policyStep.items.find((i: any) => i.type === damage.itemType);
84	  const reimbursement = damage.amount * reimbursementRatio(item);
85	  return Math.max(0, reimbursement - CLAIM_DEDUCTIBLE);
86	}
87	
88	export function runScenario(scenario: any): unknown {
89	  const results: ({ premium: number } | { payout: number })[] = [];
90	  for (const step of scenario.steps) {
91	    if (step.op === "claim") {
92	      results.push({ payout: computeClaimPayout(scenario, step) });
93	      continue;
94	    }
95	    const items = step.items;
96	    const basePrice = quoteBasePrice(items);
97	    const withCursed = applyCursedSurcharge(items, basePrice);
98	    const withEnchanted = applyEnchantedSurcharge(items, withCursed);
99	    const withLoyalty = applyLoyaltyDiscount(scenario.customer.yearsWithMHPCO, withEnchanted);
100	    const isFirstQuote = results.length === 0;
101	    const withContractAdjustment = isFirstQuote
102	      ? applyFirstInsuranceSurcharge(withLoyalty)
103	      : applySubsequentContractDiscount(withLoyalty);
104	    const premium = withContractAdjustment + FIXED_FEE;
105	    results.push({ premium });
106	  }
107	  return { results };
108	}
